sql:
SELECT model_name, last_updated
FROM predictive_models
ORDER BY last_updated DESC;

SELECT COUNT(*) AS annotation_count
FROM model_annotations
WHERE model_id = 1;

external_knowledge:
- 'Information for predictive models' refers to their names, parameters, descriptions, creation and last update dates, and the creator's ID;
- 'Latest evaluation metrics' include true match counts, computed matches, correct matches, sensitivity, specificity, and the evaluation date;
- 'Latest feedback' includes the rating and comments provided by the user, along with the feedback creation date;
- 'Version details' include the version number, release date, and a description of changes made in the latest version.

